import {timer} from "d3-timer";
import quadtree from '../d3-quadtree/quadtree.js'
// import {quadtree} from "d3-quadtree";

// https://en.wikipedia.org/wiki/Linear_congruential_generator#Parameters_in_common_use
const a = 1664525;
const c = 1013904223;
const m = 4294967296; // 2^32

function random() {
  let s = 1;
  return () => (s = (a * s + c) % m) / m;
}

function jiggle(random) {
  return (random() - 0.5) * 1e-6;
}

export default class Simulation{
	constructor(nodes, links, tickEvent){
			this.nodes = nodes;
			this.links = links;
			this.tickEvent = tickEvent;

			this.alpha = 1;																			//alpha表示simulation当前的状态
			this.alphaMin = 0.001;															//alphaMin表示simulation最终的状态
			this.alphaDecay = 1 - Math.pow(this.alphaMin, 1 / 300);	//alphaDecay表示alpha每次的衰减率
			this.alphaTarget = 0;																//alphaTarget表示最终要稳定时的状态
			this.velocityDecay = 0.6;														//velocityDecay表示速度的衰退率

			// console.log('this.alphaDecay:', this.alphaDecay);

			this.manyBodyStrength = -800;

			this.linkBias = null;
			this.linkStrengths = null;

			this.stepper = timer(this.step.bind(this));

			this.initializeNodes();
			this.initializeLinks();

	}
	step(){
		this.tick();
		if( this.tickEvent && typeof this.tickEvent === 'function' ){
			this.tickEvent();
		}
		if (this.alpha < this.alphaMin) {
			this.stepper.stop();
		}
	}
	tick(iterations){
		// console.log('tick')
		var i, n = this.nodes.length, node;

		if (iterations === undefined) {
			iterations = 1;
		}

		for (var k = 0; k < iterations; ++k) {
			this.alpha += (this.alphaTarget - this.alpha) * this.alphaDecay;

      this.forceManyBody();
			this.forceManyLinks();
			this.forceX();
			this.forceY();


			for (i = 0; i < n; ++i) {
				//fx和fy是node的固定点，如果设置了该属性则node会固定在该位置
				//这里简化了物理作用力，将当前位置坐标加上当前速度得到下一步的位置坐标
				node = this.nodes[i];
				if (node.fx == null) {
					node.x += node.vx *= this.velocityDecay;
				} else {
					node.x = node.fx;
					node.vx = 0;
				}
				if (node.fy == null) {
					node.y += node.vy *= this.velocityDecay;
				} else {
					node.y = node.fy;
					node.vy = 0;
				}
			}
		}
	}
	initializeNodes() {//初始化节点数据
		let
			initialRadius = 10,
			initialAngle = Math.PI * (3 - Math.sqrt(5));
		// console.log('nodes:', this.nodes);
		for (var i = 0, n = this.nodes.length, node; i < n; ++i) {

			node = this.nodes[i];
			node.index = i;
			if (node.fx != null){
				node.x = node.fx;
			}
			if (node.fy != null){
				node.y = node.fy;
			}
			if (isNaN(node.x) || isNaN(node.y)) {
				let radius = initialRadius * Math.sqrt(0.5 + i),
						angle = i * initialAngle;

				node.x = radius * Math.cos(angle);
				node.y = radius * Math.sin(angle);
			}
			if (isNaN(node.vx) || isNaN(node.vy)) {
				node.vx = node.vy = 0;
			}
		}
	}
	initializeLinks() {
		var 
			n = this.nodes.length,
			m = this.links.length,
			count = new Array(n),
			nodeById = new Map(this.nodes.map((d, i) => [d.id, d])),
			link;

		// console.log('nodeById:', nodeById);
		for (let i = 0; i < m; ++i) {
			link = this.links[i];
			// console.log('link.source:', link.source);

			link.source = nodeById.get(link.source);
			link.target = nodeById.get(link.target);

			count[link.source.index] = (count[link.source.index] || 0) + 1;
			count[link.target.index] = (count[link.target.index] || 0) + 1;
		}

		this.linkBias = new Array(m);
		for (let i = 0; i < m; ++i) {
			link = this.links[i];
			this.linkBias[i] = count[link.source.index] / (count[link.source.index] + count[link.target.index]);
		}

		this.linkStrengths = new Array(m);
		for (var i = 0, n = this.links.length; i < n; ++i) {
			let link = this.links[i];
			this.linkStrengths[i] = 1 / Math.min(count[link.source.index], count[link.target.index]);
		}

	}
	forceManyLinks() {
		let iterations = 1,
				distance = 30;

		for (var k = 0, n = this.links.length; k < iterations; ++k) {
			for (var i = 0, link, source, target, x, y, l, b; i < n; ++i) {
				link = this.links[i];
				source = link.source;
				target = link.target;
				x = target.x + target.vx - source.x - source.vx || jiggle(random);
				y = target.y + target.vy - source.y - source.vy || jiggle(random);
				l = Math.sqrt(x * x + y * y);
				l = (l - distance) / l * this.alpha * this.linkStrengths[i];
				x *= l;
				y *= l;
				target.vx -= x * (b = this.linkBias[i]);
				target.vy -= y * b;
				source.vx += x * (b = 1 - b);
				source.vy += y * b;
			}
		}
	}
	forceManyBody() {
		let nodes = this.nodes,
				alpha = this.alpha,
				node

    var
		    i, n = nodes.length,
		    tree = quadtree({
		    					getX(d){
		    						return d.x;
		    					},
		    					getY(d){
		    						return d.y;
		    					}
						    })
		    				.addArray(nodes)
		    				.initRange()
						    .visitAfter((quad)=>{
							    var strength = 0, q, c, weight = 0, x, y, i;

							    // For internal nodes, accumulate forces from child quadrants.
							    if (quad.length) {
							      for (x = y = i = 0; i < 4; ++i) {
							        if ((q = quad[i]) && (c = Math.abs(q.value))) {
							          strength += q.value;
							          weight += c;
							          x += c * q.x;
							          y += c * q.y;
							        }
							      }
							      quad.x = x / weight;
							      quad.y = y / weight;
							    }

							    // For leaf nodes, accumulate forces from coincident quadrants.
							    else {
							      q = quad;
							      q.x = q.data.x;
							      q.y = q.data.y;

							      strength += this.manyBodyStrength;
							    }

							    quad.value = strength;
							  });

		let 
			distanceMin2 = 1,
			distanceMax2 = Infinity,
			theta2 = 0.81;

    for (i = 0; i < n; ++i){
    	node = nodes[i];
    	tree.visit((quad)=>{
		    if (!quad.value) {
		    	return true;
		    }

		    let 
		    		x1 = quad.x0,
		    		_ = quad.y0,
		    		x2 = quad.x1,
				    x = quad.x - node.x,
		        y = quad.y - node.y,
		        w = x2 - x1,
		        l = x * x + y * y;

		    // Apply the Barnes-Hut approximation if possible.
		    // Limit forces for very close nodes; randomize direction if coincident.
		    if (w * w / theta2 < l) {
		      if (l < distanceMax2) {
		        if (x === 0) {
		        	x = jiggle(random);
		        	l += x * x;
		        }
		        if (y === 0) {
		        	y = jiggle(random);
		        	l += y * y;
		        }
		        if (l < distanceMin2) {
		        	l = Math.sqrt(distanceMin2 * l);
		        }
		        node.vx += x * quad.value * alpha / l;
		        node.vy += y * quad.value * alpha / l;
		      }
		      return true;
		    }
		    // Otherwise, process points directly.
		    else if (quad.length || l >= distanceMax2) {
		    	return;
		    }

		    // Limit forces for very close nodes; randomize direction if coincident.
		    if (quad.data !== node) {
		      if (x === 0) {
		      	x = jiggle(random);
		      	l += x * x;
		      }
		      if (y === 0) {
		      	y = jiggle(random);
		      	l += y * y;
		      }
		      if (l < distanceMin2) {
		      	l = Math.sqrt(distanceMin2 * l);
		      }
		    }

		    if(quad.data !== node){

		      w = this.manyBodyStrength * alpha / l;
		      node.vx += x * w;
		      node.vy += y * w;
		    }
		  });
    }
	}
	forceX() {
		let xStrength = 0.1,
				xz = 0;

		for (var i = 0, n = this.nodes.length, node; i < n; ++i) {
			node = this.nodes[i];
			node.vx += (xz - node.x) * xStrength * this.alpha;
		}
	}
	forceY() {
		let yStrength = 0.1,
				yz = 0;

		for (var i = 0, n = this.nodes.length, node; i < n; ++i) {
			node = this.nodes[i];
			node.vy += (yz - node.y) * yStrength * this.alpha;
		}
	}
}