<template>
	<div
		class="container"
		ref="container"></div>
</template>

<script>
	import * as d3 from 'd3'
	import Simulation from './d3-force/simulation.js'
	import data from './assets/mobile-patent-suits.json';

	export default {
		mounted(){
			let 
				container = this.$refs.container,
				width = this.width = container.clientWidth,
				height = this.height = container.clientHeight,

				types = ["licensing", "suit", "resolved"],
				color = d3.scaleOrdinal(types, d3.schemeCategory10),

				links = data.links,
				nodes = data.nodes,


				simulation = new Simulation(nodes, links, ()=>{
					link.attr("d", linkArc);
					node.attr("transform", d => `translate(${d.x},${d.y})`);
				}),

				svg = d3.select(container)
					.append('svg')
					.attr("viewBox", [-width / 2, -height / 2, width, height])
					.style("font", "12px sans-serif");

			svg.append("defs").selectAll("marker")
				.data(types)
				.join("marker")
				.attr("id", d => `arrow-${d}`)
				.attr("viewBox", "0 -5 10 10")
				.attr("refX", 15)
				.attr("refY", -0.5)
				.attr("markerWidth", 6)
				.attr("markerHeight", 6)
				.attr("orient", "auto")
				.append("path")
				.attr("fill", color)
				.attr("d", "M0,-5L10,0L0,5");

			let
				link = svg.append("g")
					.attr("fill", "none")
					.attr("stroke-width", 1.5)
					.selectAll("path")
					.data(links)
					.join("path")
					.attr("stroke", d => color(d.type))
					.attr("marker-end", d => `url(${new URL(`#arrow-${d.type}`, document.location)})`),

				node = svg.append("g")
					.attr("fill", "currentColor")
					.attr("stroke-linecap", "round")
					.attr("stroke-linejoin", "round")
					.selectAll("g")
					.data(nodes)
					.join("g")

			node.append("circle")
				.attr("stroke", "white")
				.attr("stroke-width", 1.5)
				.attr("r", 4);

			function linkArc(d) {
				const r = Math.hypot(d.target.x - d.source.x, d.target.y - d.source.y);
				return `
				M${d.source.x},${d.source.y}
				A${r},${r} 0 0,1 ${d.target.x},${d.target.y}
				`;
			}
		}
	}
</script>